opam option jobs=1 2>&1 | tail -1
opam install -y --jobs=1 coq.8.16.1 2>&1 | tail -6; echo "COQEXIT ${PIPESTATUS[0]}"; ls -l /root/.opam/cc/bin/coqc 2>&1

