opam install -y --jobs=1 menhir.20230608 2>&1 | tail -5; echo "EXIT ${PIPESTATUS[0]}"
ls /root/.opam/cc/lib/menhirLib/ | grep -i general

export OPAMROOT=/root/.opam OPAMSWITCH=cc; eval $(opam env --switch=cc)
cd /tmp/CompCert
make -j1 2>&1 | tail -15; echo "MAKEEXIT ${PIPESTATUS[0]}"; ls -l /tmp/CompCert/ccomp 2>&1

export OPAMROOT=/root/.opam OPAMSWITCH=cc; eval $(opam env --switch=cc)
cd /tmp/CompCert
make -j1 2>&1 | tail -15; echo "MAKEEXIT ${PIPESTATUS[0]}"; ls -l /tmp/CompCert/ccomp 2>&1

cd /tmp/CompCert
./ccomp -v 2>&1 | head -2
cat > /tmp/hello.c <<'EOF'
#include <stdio.h>
int fib(int n){return n<2?n:fib(n-1)+fib(n-2);}
int main(){printf("fib10=%d\n", fib(10)); return 0;}
EOF
./ccomp -o /tmp/hello /tmp/hello.c 2>&1 | tail -3 && /tmp/hello

